import{_ as t,o,c as s,ac as r}from"./chunks/framework.RaldHO_f.js";const g=JSON.parse('{"title":"你好，博客世界 —— 开始用 VitePress 写作","description":"这是我的第一篇博客，记录博客搭建过程和写作初衷。","frontmatter":{"title":"你好，博客世界 —— 开始用 VitePress 写作","date":"2026-04-18T00:00:00.000Z","tags":["VitePress","博客搭建","写作"],"categories":["随笔"],"description":"这是我的第一篇博客，记录博客搭建过程和写作初衷。","cover":"https://images.unsplash.com/photo-1499750310107-5fef28a66643?w=800&q=80"},"headers":[],"relativePath":"posts/hello-world.md","filePath":"posts/hello-world.md","lastUpdated":null}'),a={name:"posts/hello-world.md"};function l(i,e,n,d,p,h){return o(),s("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1776470400000"},[...e[0]||(e[0]=[r('<h1 id="你好-博客世界" tabindex="-1">你好，博客世界 <a class="header-anchor" href="#你好-博客世界" aria-label="Permalink to &quot;你好，博客世界&quot;">​</a></h1><blockquote><p>种一棵树最好的时间是十年前，其次是现在。</p></blockquote><p>很早就想拥有一个自己的技术博客，用来沉淀学习的过程，分享踩坑的经验。今天终于动手了。</p><h2 id="为什么选择-vitepress" tabindex="-1">为什么选择 VitePress <a class="header-anchor" href="#为什么选择-vitepress" aria-label="Permalink to &quot;为什么选择 VitePress&quot;">​</a></h2><p>市面上博客方案很多——Hexo、Hugo、Next.js、Ghost……最终我选择了 <a href="https://vitepress.dev/" target="_blank" rel="noreferrer">VitePress</a>，理由如下：</p><ul><li><strong>零依赖的 Markdown 写作体验</strong> —— 直接写 <code>.md</code> 文件，没有任何心理负担</li><li><strong>Vue 生态无缝集成</strong> —— 可以在 Markdown 里写 Vue 组件</li><li><strong>Vite 极速构建</strong> —— 热更新快如闪电，写作反馈即时</li><li><strong>GitHub Pages 免费托管</strong> —— push 代码即发布，省心省力</li></ul><h2 id="博客的定位" tabindex="-1">博客的定位 <a class="header-anchor" href="#博客的定位" aria-label="Permalink to &quot;博客的定位&quot;">​</a></h2><p>这不是一个只写前端的博客。这里会记录我在技术世界里探索的一切——</p><ol><li><strong>系统设计</strong> —— 架构思考、高可用、分布式的每一个有趣问题</li><li><strong>后端开发</strong> —— Go / Python / Node.js 的语言特性与实战经验</li><li><strong>前端工程</strong> —— 现代框架、工具链、性能调优</li><li><strong>AI 与大模型</strong> —— 应用落地、提示工程、工具链探索</li><li><strong>效率工具</strong> —— 开发环境、自动化、让日常工作更顺滑的一切</li><li><strong>学习笔记</strong> —— 读书摘要、课程精华、技术文档的深度解读</li></ol><p>技术本来就是一张网，只盯着某一个节点，会错过很多有趣的连接。</p><h2 id="一个小目标" tabindex="-1">一个小目标 <a class="header-anchor" href="#一个小目标" aria-label="Permalink to &quot;一个小目标&quot;">​</a></h2><blockquote><p><strong>坚持写作，每月至少 2 篇。</strong></p></blockquote><p>欢迎通过 GitHub Discussions 留言交流，或者直接提 Issue。</p><hr><p><em>写于 2026 年 4 月，武汉。</em></p>',15)])])}const u=t(a,[["render",l]]);export{g as __pageData,u as default};
